mapper.update:
UPDATE TWORK_INFO_APP_DOWN
   SET APPVERSION = #{appversion}
      ,FILENM = #{filenm}
      ,FILEPATH = #{filepath}
      ,APPDOWN_YN = #{appdown_yn}
	  ,UPDATEDATE = #{sysdate}
	  ,UPDATEURKEY = #{surkey}
 WHERE  
      APPDOWNKEY = #{appdownkey}

		UPDATE TWORK_INFO_APP_DOWN
		   SET APPDOWN_YN = 'N'
			  ,UPDATEDATE = #{sysdate}
			  ,UPDATEURKEY = #{surkey}
		 WHERE  
		      APPDOWNKEY != #{appdownkey}
          AND APPDOWN_YN = 'Y'
